public class SimplePartitioner implements Partitioner {

	private static final String PARTITION_KEY = "partition";

	@Override
	public Map<String, ExecutionContext> partition(int gridSize) {
		Map<String, ExecutionContext> map = CollectionUtils.newHashMap(gridSize);
		for (int i = 0; i < gridSize; i++) {
			map.put(PARTITION_KEY + i, new ExecutionContext());
		}
		return map;
	}

}

class JobInstanceRowMapper implements RowMapper<JobInstance> {

	@Override
	public JobInstance mapRow(ResultSet rs, int rowNum) throws SQLException {
		long jobInstanceId = rs.getLong("JOB_INSTANCE_ID");
		String jobName = rs.getString("JOB_NAME");
		JobInstance jobInstance = new JobInstance(jobInstanceId, jobName);
		// should always be at version=0 because they never get updated
		jobInstance.incrementVersion();
		return jobInstance;
	}

}

public class JobInstanceConverter {

	public org.springframework.batch.core.job.JobInstance toJobInstance(JobInstance source) {
		return new org.springframework.batch.core.job.JobInstance(source.getJobInstanceId(), source.getJobName());
	}

	public JobInstance fromJobInstance(org.springframework.batch.core.job.JobInstance source) {
		JobInstance jobInstance = new JobInstance();
		jobInstance.setJobName(source.getJobName());
		jobInstance.setJobInstanceId(source.getInstanceId());
		return jobInstance;
	}

}

@Aspect
public class JobScopeManager {

	@Around("execution(void org.springframework.batch.core.job.Job+.execute(*)) && target(job) && args(jobExecution)")
	public void execute(Job job, JobExecution jobExecution) throws JobInterruptedException {
		JobSynchronizationManager.register(jobExecution);
		try {
			job.execute(jobExecution);
		}
		finally {
			JobSynchronizationManager.release();
		}
	}

}

@Aspect
public class StepScopeManager {

	@Around("execution(void org.springframework.batch.core.step.Step+.execute(*)) && target(step) && args(stepExecution)")
	public void execute(Step step, StepExecution stepExecution) throws JobInterruptedException {
		StepSynchronizationManager.register(stepExecution);
		try {
			step.execute(stepExecution);
		}
		finally {
			StepSynchronizationManager.release();
		}
	}

}

@Deprecated(since = "6.0", forRemoval = true)
abstract class BatchListenerFactoryHelper {

	public static <T> List<T> getListeners(StepListener[] listeners, Class<? super T> cls) {
		List<T> list = new ArrayList<>();
		for (StepListener stepListener : listeners) {
			if (cls.isAssignableFrom(stepListener.getClass())) {
				@SuppressWarnings("unchecked")
				T listener = (T) stepListener;
				list.add(listener);
			}
		}
		return list;
	}

}

public class ColumnMapItemPreparedStatementSetter implements ItemPreparedStatementSetter<Map<String, Object>> {

	@Override
	public void setValues(Map<String, Object> item, PreparedStatement ps) throws SQLException {
		Assert.isInstanceOf(Map.class, item, "Input to map PreparedStatement parameters must be of type Map.");
		int counter = 1;
		for (Object value : item.values()) {
			StatementCreatorUtils.setParameterValue(ps, counter, SqlTypeValue.TYPE_UNKNOWN, value);
			counter++;
		}
	}

}

