final class PropertiesToStringConverter implements Converter<Properties, String> {

	@Override
	public String convert(Properties source) {
		try {
			ByteArrayOutputStream os = new ByteArrayOutputStream(256);
			source.store(os, null);
			return os.toString(StandardCharsets.ISO_8859_1);
		}
		catch (IOException ex) {
			// Should never happen.
			throw new IllegalArgumentException("Failed to store [" + source + "] into String", ex);
		}
	}

}

final class StringToCharacterConverter implements Converter<String, @Nullable Character> {

	@Override
	public @Nullable Character convert(String source) {
		if (source.isEmpty()) {
			return null;
		}
		if (source.length() > 1) {
			throw new IllegalArgumentException(
					"Can only convert a [String] with length of 1 to a [Character]; string value '" + source + "'  has length of " + source.length());
		}
		return source.charAt(0);
	}

}

public class WebSocketUpgradeHandlerPredicate implements BiPredicate<Object, ServerWebExchange> {

	@Override
	public boolean test(Object handler, ServerWebExchange exchange) {
		if (handler instanceof WebSocketHandler) {
			HttpMethod method = exchange.getRequest().getMethod();
			String header = exchange.getRequest().getHeaders().getUpgrade();
			return (HttpMethod.GET.equals(method) && header != null && header.equalsIgnoreCase("websocket"));
		}
		return true;
	}

}

